PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE rules (
	id INTEGER NOT NULL,
	name VARCHAR(255) NOT NULL,
	field_mapping TEXT, 
	extract_config TEXT, 
	request_config TEXT, 
	list_selector_type VARCHAR(50), 
	list_selector VARCHAR(1000), 
	list_item_selector VARCHAR(1000), 
	detail_url_pattern VARCHAR(1000), 
	title_selector_type VARCHAR(50), 
	title_selector VARCHAR(1000), 
	content_selector_type VARCHAR(50), 
	content_selector VARCHAR(1000), 
	author_selector_type VARCHAR(50), 
	author_selector VARCHAR(1000), 
	publish_time_selector_type VARCHAR(50), 
	publish_time_selector VARCHAR(1000), 
	cover_image_selector VARCHAR(1000), 
	exclude_patterns TEXT, 
	auth_type VARCHAR(50), 
	auth_config TEXT, 
	proxy_config VARCHAR(500), 
	delay_min INTEGER, 
	delay_max INTEGER, 
	user_agent VARCHAR(500), 
	status VARCHAR(20), 
	cron_expression VARCHAR(100), 
	created_at DATETIME,
	updated_at DATETIME,
	strategy VARCHAR(50) DEFAULT "auto",
	render VARCHAR(20),
	content_type VARCHAR(20),
	PRIMARY KEY (id)
);
CREATE TABLE rule_levels (
	id INTEGER NOT NULL, 
	rule_id INTEGER, 
	level INTEGER NOT NULL, 
	name VARCHAR(100), 
	url VARCHAR(1000), 
	url_type VARCHAR(20), 
	selector_type VARCHAR(20), 
	link_selector VARCHAR(1000), 
	content_selector VARCHAR(1000), 
	exclude_patterns TEXT, 
	is_final BOOLEAN, 
	action_type VARCHAR(20), 
	action_config TEXT, 
	pagination_type VARCHAR(20), 
	pagination_selector VARCHAR(500), 
	pagination_max INTEGER, 
	created_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(rule_id) REFERENCES rules (id) ON DELETE CASCADE
);
CREATE TABLE articles (
	id INTEGER NOT NULL, 
	rule_id INTEGER, 
	url VARCHAR(1000) NOT NULL, 
	title VARCHAR(500), 
	summary TEXT, 
	author VARCHAR(255), 
	publish_time DATETIME, 
	cover_image VARCHAR(500), 
	markdown_file VARCHAR(500), 
	status VARCHAR(20),
	error_message TEXT,
	tags TEXT,
	created_at DATETIME,
	updated_at DATETIME,
	PRIMARY KEY (id),
	FOREIGN KEY(rule_id) REFERENCES rules (id) ON DELETE CASCADE
);
CREATE TABLE jobs (
	id INTEGER NOT NULL, 
	rule_id INTEGER, 
	status VARCHAR(20), 
	trigger_type VARCHAR(20), 
	started_at DATETIME, 
	finished_at DATETIME, 
	articles_count INTEGER, 
	success_count INTEGER, 
	failed_count INTEGER, 
	error_message TEXT, 
	created_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(rule_id) REFERENCES rules (id) ON DELETE CASCADE
);
CREATE TABLE logs (
	id INTEGER NOT NULL, 
	job_id INTEGER, 
	level VARCHAR(20), 
	message TEXT, 
	created_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(job_id) REFERENCES jobs (id) ON DELETE CASCADE
);
CREATE INDEX ix_rules_id ON rules (id);
CREATE INDEX ix_rule_levels_id ON rule_levels (id);
CREATE INDEX ix_articles_id ON articles (id);
CREATE INDEX ix_jobs_id ON jobs (id);
CREATE INDEX ix_logs_id ON logs (id);
COMMIT;
