INSERT INTO articles VALUES(11,11,'https://36kr.com/p/3732100232298503?f=rss','“我的前额叶罢工了”，年轻人争相确诊“网红病”？',unistr('<p>当代年轻人对待病的态度，像薛定谔的猫一般充满矛盾。</p>\u000a  <p>有时讳疾忌医，不敢看自己的体检报告，对报告里已确诊的小结节、轻度脂肪肝、胃炎装聋作哑，安慰自己没啥大事。</p>\u000a  <p>有时又上赶着帮自己“确诊”新疾病：“我说我怎么天天活人微死还犯懒呢，原来我是前额叶受损啊。”</p>\u000a  <p class="image-wrapper"><img data-img-size-val="831,557" src="https://img.36krcdn.com/hsossms/20260321/v2_8569f8b8bb184111a4524a0cb5b2c004@6076018_oswg281559oswg831oswg557_img_000?x-oss-process=image/format,jpg/interlace,1"></p>\u000a  <p class="img-desc">网友疯传的前额叶梗图。（图/社交平台截图）</p>\u000a  <p>最近，又轮到了前额叶。</p>\u000a  <p>这个原本常见于神经科学教科书中的专业术语，近期一跃成为了热搜常客。</p>\u000a  <p>'),NULL,NULL,NULL,'data/articles/004a893a9b.md','success',NULL,'2026-03-22 02:44:37.559687','2026-03-22 02:44:37.559694');
INSERT INTO articles VALUES(12,11,'https://36kr.com/p/3732001538490631?f=rss','9点1氪：傅盛凌晨开撕周鸿祎称“被欠1个亿”，360回应；字节跳动413亿元卖掉沐瞳科技；伊朗战事持续或致油价升至180美元',unistr('<h2><strong>今日热点导览</strong></h2>\u000a  <p>商务部部长王文涛会见苹果公司首席执行官库克</p>\u000a  <p>贾国龙起家的西贝首店将缩减一半经营面积</p>\u000a  <p>特斯拉计划采购中国光伏设备？企业回应：确有此事</p>\u000a  <p>针对“漂白鸡爪”等“3·15”晚会曝光问题，多地立案溯源打击</p>\u000a  <p>中国学生平均留学预算超60万</p>\u000a  <h2><strong>TOP3大新闻</strong></h2>\u000a  <p><strong>傅盛微信群里开撕周鸿祎称“欠钱不还”，360回应</strong></p>\u000a  <p>3月20日，社交媒体流传的截图显示，当天凌晨，猎豹移动董事长兼CEO傅盛在微信聊天群里“开撕”360创始人周鸿祎，指责周鸿祎“欠钱不还，并遭拉黑”。</p>\u000a  <p>3月20日，360集团回应称，“我们更关注把产品做好，让每个人都能用上安全便捷的360安全龙虾。企业家打造个人影响力，归根结底还是要靠产品和用户价值，而不是依赖情绪表达或话题炒作。对于谣言和失实信息，360集团已启动证据保全，并将通过法律途径依法处理。”（澎湃新闻）<'),NULL,NULL,NULL,'data/articles/1772fd1c9a.md','success',NULL,'2026-03-22 02:44:37.564728','2026-03-22 02:44:37.564733');
INSERT INTO articles VALUES(13,11,'https://36kr.com/p/3731378273828868?f=rss','万物云：与万科关联应收账款余额仅剩20.6亿，业务独立性持续增强',unistr('<p>3月19日晚间，万物云空间科技服务股份有限公司发布2025年度业绩报告。报告期内，万物云实现营业收入372.7亿元，同比增长2.7%，剔除开发商相关业务后，营收同比增长8.4%；核心净利润约21.3亿元，同比微增0.8%；归母净利润7.7亿元，同比出现较大幅度下滑。</p>\u000a  <p class="image-wrapper"><img data-img-size-val="4000,2666" src="https://img.36krcdn.com/hsossms/20260320/v2_3930db0239164fdd83509241de181dc6@337187376_oswg4382727oswg4000oswg2666_img_jpg?x-oss-process=image/quality,q_80/format,jpg/interlace,1"></p>\u000a  <p class="img-desc">业绩发布会现场</p>\u000a  <p>万物云董事长朱保全在业绩发布会上表示，关联开发商（万科）产生的坏账及资产摊销所带来的负向影响是利润下滑的主要原因，2025年全年因此产生'),NULL,NULL,NULL,'data/articles/2b857ea978.md','success',NULL,'2026-03-22 02:44:37.569426','2026-03-22 02:44:37.569428');
INSERT INTO articles VALUES(14,11,'https://36kr.com/p/3731169592918273?f=rss','氪星晚报｜迪卡侬正式入驻拼多多；特斯拉计划2026年批量交付Semi电动卡车，价格或低于30万美元；消息人士：马斯克团队采购光伏设备预计将在5月第一周发货',unistr('<h2><strong>大公司：</strong></h2>\u000a  <p><a target="_blank" rel="noopener noreferrer" href="https://36kr.com/newsflashes/3731055603384321"><strong>小鹏汽车：预计第一季度交付量61000辆-66000辆，同比减少29.8%-35.1%</strong></a></p>\u000a  <p>36氪获悉，小鹏汽车发布2025年第四季度及全年财报。财报显示，对于2026年第一季度，本公司预期汽车交付量将介乎61000-66000辆，按年减少约29.79%-35.11%。总收入将介乎122.0亿元-132.8亿元，按年减少约16.01%-22.84%。</p>\u000a  <p><a target="_blank" rel="noopener noreferrer" href="https://36kr.com/newsflashes/3731035141226501"><strong>北京汽车：王昊由于工作变动将不再担任董事长，提名张国富任董事长</strong></a></'),NULL,NULL,NULL,'data/articles/713c6204cf.md','success',NULL,'2026-03-22 02:44:37.573048','2026-03-22 02:44:37.573053');
INSERT INTO articles VALUES(15,11,'https://36kr.com/p/3731096049795078?f=rss','阿迪达斯，不看好2026的自己',unistr('<p><strong>作者 |</strong>&nbsp;谢芸子</p>\u000a  <p><strong>编辑 |&nbsp;</strong> 张帆&nbsp;</p>\u000a  <p><strong>封面来源 |&nbsp;</strong> 企业官微&nbsp;</p>\u000a  <p>阿迪达斯几乎交出了近年来的最好业绩。</p>\u000a  <p>在彻底摆脱“椰子”的第一个完整财年，这家老牌德国体育用品集团2025年的全球营收达到248亿欧元（约合1993亿元人民币），营收增幅13%，创历史新高；归属股东净利润为13.4亿欧元，毛利率也创历史新高达到51.6%。</p>\u000a  <p class="image-wrapper"><img data-img-size-val="700,365" src="https://img.36krcdn.com/hsossms/20260320/v2_825ec130a9114be2be141c569dbcb983@394564713_oswg52543oswg700oswg365_img_000?x-oss-process=image/format,jpg/inte'),NULL,NULL,NULL,'data/articles/ee9357710b.md','success',NULL,'2026-03-22 02:44:37.576605','2026-03-22 02:44:37.576607');
INSERT INTO articles VALUES(16,11,'https://36kr.com/p/3731094987407617?f=rss','RENOGY 如果新能源：如何用16年时间打造一家Global Native公司｜出海踏浪者',unistr('<p>无论是欧洲家庭的户外露营、北美车库的应急备用，还是日本公寓中的防灾储备柜，便携储能产品的身影已遍布全球。</p>\u000a  <p>便携储能在欧美地区尤其受欢迎，这一方面源于当地长期以来浓厚的户外露营文化。The Dyrt发布报告称，2024年约有8110万美国人进行了露营活动（包括传统帐篷露营、房车露营等），其中约580万为首次露营者。另一方面，露营的普及对稳定的户外电力供应提出更高要求，而这恰恰也是露营玩家们长期难以解决的痛点。美国部分地区电网老化问题突出，加州等地在山火爆发季节还会经常进行预防性断电。</p>\u000a  <p>众所周知，<strong>便携储能赛道长期以来都是中国品牌的“主场”，凭借成熟的供应链体系，中国品牌在全球市场的份额已超过九成。</strong>面对日益增长且多样化的能源需求，RENOGY如果新能源没有和大多数品牌一样去“卷”轻量便携的标准化移动电源赛道，而是专注于房车、游艇、特种车辆等高电力需求环境的专业用电场景。</p>\u000a  <p>目前RENOGY销售的产品包括太阳能组件、控制器、储能电池、逆变器以及智慧能源管理系统，构成完整的离网电力系统（Off-Grid '),NULL,NULL,NULL,'data/articles/6a01504c25.md','success',NULL,'2026-03-22 02:44:37.580054','2026-03-22 02:44:37.580066');
INSERT INTO articles VALUES(17,11,'https://36kr.com/p/3731048121647361?f=rss','沙特土豪超60亿美元收购沐瞳：公司架构不变，张云帆仍是CEO',unistr('<p>3月20日，沐瞳科技发布公司内部信，宣布公司已被沙特阿拉伯主权财富基金全资控股的游戏巨头Savvy Games Group（简称Savvy）收购。</p>\u000a  <p>自字节游戏业务调整后，这场交易就早有传闻，去年底已经有了大致轮廓。双方在2025下半年正式启动谈判，并在2026年初围绕核心条款达成共识，最后Savvy以超60亿美元的价格收购沐瞳的全部股权。</p>\u000a  <p>这场交易距离字节收购沐瞳只有5年——彼时的收购价格为40亿美元，如果考虑到谈判和双方讨论时间，这个出售间隔可能更短。</p>\u000a  <p>而从内部信来看，此次交易后，沐瞳的管理结构仍旧保持不变，张云帆会继续担任沐瞳CEO。在此基础上，公司还会针对员工的历史贡献及未来业绩，设置多项激励方案。</p>\u000a  <p>以下是内部信全文：</p>\u000a  <p>大家好，最近公司和Savvy Games Group签署了协议，双方将在未来一段时间内完成交易。交易完成后，沐瞳将成为Savvy的全资子公司。与此同时，沐瞳的管理结构保持不变，沐瞳仍是一家总部位于上海的公司。我本人也将继续担任沐瞳CEO，和管理团队一起继续带领公司向前发'),NULL,NULL,NULL,'data/articles/84fdf644eb.md','success',NULL,'2026-03-22 02:44:37.583822','2026-03-22 02:44:37.583824');
INSERT INTO articles VALUES(18,11,'https://36kr.com/p/3730996090192130?f=rss','求购Anthropic老股份额；求购多家机器人公司老股份额｜资情留言板第181期',unistr('<p>资产交易市场，信息瞬息万变，消息真假难辨，即使买卖双方花费大量的时间、精力，推动成交往往困难重重。为了能够帮助买卖双方更快速链接市场信息和潜在交易对手，避免不必要的投入与浪费，我们特地打造了这样一档栏目。</p>\u000a  <p>本文是这个栏目的第181期。如果你对本文提到的相关的交易线索感兴趣，希望接触这些潜在的交易对手，或者如果你手中直接握有希望交易的资金或者资产，欢迎与我们联系。（邮箱：zcjy@36kr.com）&nbsp;</p>\u000a  <h2><strong>一、本月新增</strong></h2>\u000a  <h2><strong>1、求购Anthropic老股份额（预期估值面议）</strong></h2>\u000a  <p>交易价格：预期估值面议</p>\u000a  <p>资产规模：约5000万-1亿美元</p>\u000a  <p>交易方式：直接老股交易，可以接受进入结构</p>\u000a  <p>联系方式：zcjy@36kr.com</p>\u000a  <h2><strong>2、求购乐聚机器人老股份额（预期估值面议）</strong></h2>\u000a  <p>交易价格：预期估值面议</p>\u000a  <p>资产规模：约3'),NULL,NULL,NULL,'data/articles/7be05c05a2.md','success',NULL,'2026-03-22 02:44:37.586688','2026-03-22 02:44:37.586689');
INSERT INTO articles VALUES(19,11,'https://36kr.com/p/3730644353286150?f=rss','从能力到商品：Skills市场正在重塑开发者的生产方式',unistr('<p>技能是产业竞争力的重要体现方式之一 。在上海，一场 AI 时代的技能革命也在悄然展开——进入 2026 年，新赛季的竞争不再是大模型间的参数比拼，而是谁能真正走进工厂、实验室和写字楼，变成“会做事”的生产力工具。开源项目 OpenClaw 的迅速走红，折射出以 Skills 市场等形式的开放共享的新趋势——或许正是那把撬开这场 Agent 变革的锁钥。</p>\u000a  <p>简言之， Skills 市场是智能体的“技能商店”：开发者将专业能力封装为标准化模块，供全球智能体按需调用。这是开发工具的升级， 更是生产关系的深层重构。&nbsp;</p>\u000a  <p class="image-wrapper"><img data-img-size-val="1000,459" src="https://img.36krcdn.com/hsossms/20260320/v2_43d7c9d2d9444798b1929cb39d186cff@5868219_oswg101784oswg1000oswg459_img_000?x-oss-process=image/format,jpg/interl'),NULL,NULL,NULL,'data/articles/dd9f10fa9d.md','success',NULL,'2026-03-22 02:44:37.589500','2026-03-22 02:44:37.589502');
INSERT INTO articles VALUES(20,11,'https://36kr.com/p/3729647028960903?f=rss','港中文95后博士、OPPO员工做了款AI可穿戴硬件，要成为用户全天候情感导师｜硬氪首发',unistr('<p>作者｜黄楠</p>\u000a  <p>编辑｜袁斯来</p>\u000a  <p>硬氪获悉，深圳十镜科技有限公司（以下简称“十镜科技”）近日完成数千万元天使轮融资，本轮由元禾原点投资，融资资金将主要用于核心技术研发、产品结构迭代优化及小批量量产落地。首款产品Spiro计划于&nbsp;2026年4月在北美独立站上线、6月量产。</p>\u000a  <p>十镜科技成立于2025年7月，创始人兼CEO赵之赫是一名95后连续创业者，博士毕业于香港中文大学，他曾出任智能穿戴硬件企业物启科技CEO，并推出全球首款AI情绪吊坠Nuna。联合创始人曾任职于大疆、安克、OPPO等企业，拥有多年的产品落地经验与成熟的市场化运作能力。</p>\u000a  <p>智能穿戴行业正经历一场隐性的代际更替。过去几年，功能叠加始终是行业的主流叙事，更多传感器、更精准的数据、更专业的分析，被默认为产品进化的主导方向。但AI Pin等市场遇冷，暴露了这一路径的深层困境：当硬件被定义为“工具”，其价值就被锁死在特定使用场景之中，脱离场景，用户容易失去持续佩戴的动力。</p>\u000a  <p>新鲜感退潮后的高闲置率，正在倒逼行业重新思考AI可穿戴硬件的底层逻'),NULL,NULL,NULL,'data/articles/5b246ee06b.md','success',NULL,'2026-03-22 02:44:37.592806','2026-03-22 02:44:37.592808');
INSERT INTO articles VALUES(21,11,'https://36kr.com/newsflashes/3733475828695296?f=rss','北京高职自主招生报名今天启动','2026年北京市高等职业教育自主招生报名工作今天（22日）启动，到3月26日结束。今年共有34所高职院校参与自主招生。各招生院校将按照相关规定自主组织入学考试。每名考生限报一所院校。已参加北京市2026年高考报名的统考考生和单考考生均可报名参加高职自主招生。高职自主招生一般为“文化素质+职业技能”考试。需要提醒考生的是，被录取的考生不再参加当年高考。',NULL,NULL,NULL,'data/articles/7d1ddbc57f.md','success',NULL,'2026-03-22 02:44:37.595277','2026-03-22 02:44:37.595278');
INSERT INTO articles VALUES(22,11,'https://36kr.com/newsflashes/3733492798095623?f=rss','小阔集团联合华晨宇共创全新日化家居品牌“重点”','3月22日，小阔集团与华晨宇联合创立的全新日化家居品牌“重点”正式发布，华晨宇出任品牌联合创始人。该品牌聚焦传统日化家居长期被忽略的微观需求，致力于为消费者提供细节、舒适、安全的日化家居解决方案。“重点”品牌的推出，将进一步完善小阔集团多品牌、多赛道的日化生态矩阵。',NULL,NULL,NULL,'data/articles/f533591b18.md','success',NULL,'2026-03-22 02:44:37.599334','2026-03-22 02:44:37.599337');
INSERT INTO articles VALUES(23,11,'https://36kr.com/newsflashes/3733474717204743?f=rss','首钢与中国一汽成功合作研发2.4GPa级超高强度热成形钢','3月22日，首钢集团公众号消息，近日，首钢联合中国一汽成功合作完成2.4GPa（2400MPa）级热成形钢的材料开发与应用验证。这是全球汽车用材领域的又一次极限突破。该材料的成功开发，标志着我国在高性能汽车用钢应用领域迈入全球领先行列，为汽车安全与轻量化提供了革命性材料解决方案。',NULL,NULL,NULL,'data/articles/0b01b21351.md','success',NULL,'2026-03-22 02:44:37.603255','2026-03-22 02:44:37.603257');
INSERT INTO articles VALUES(24,11,'https://36kr.com/newsflashes/3733433736544263?f=rss','汤臣倍健：目前已在东南亚主要国家进行布局','3月22日，汤臣倍健在业绩电话会表示，公司将以本土化需求为核心驱动国际业务扩张，目前已在东南亚主要国家进行布局，将加速扩大东南亚线下渠道覆盖，推动线上渠道实现增长突破。',NULL,NULL,NULL,'data/articles/e5ea0bb0f6.md','success',NULL,'2026-03-22 02:44:37.606087','2026-03-22 02:44:37.606088');
INSERT INTO articles VALUES(25,11,'https://36kr.com/newsflashes/3733430950510592?f=rss','中国发展高层论坛今日召开，蓝佛安、潘功胜将发声','据中国发展高层论坛微信公众号消息，中国发展高层论坛2026年年会将于3月22日至23日在北京召开，主题为“‘十五五’的中国：高质量发展与共创新机遇”。根据中国发展高层论坛2026年年会日程，财政部部长蓝佛安、中国人民银行行长潘功胜将在“宏观政策与高质量发展专题研讨会”上发言。',NULL,NULL,NULL,'data/articles/9edaa165aa.md','success',NULL,'2026-03-22 02:44:37.609029','2026-03-22 02:44:37.609032');
INSERT INTO articles VALUES(26,11,'https://36kr.com/newsflashes/3733429674868992?f=rss','清明假期火车票开售 深圳铁路部门预计发送旅客181.4万人次','随着清明假期临近，不少家庭已将扫祭追思、踏青出游提上日程。记者从深圳铁路部门获悉，2026年清明假期首日火车票已于3月21日正式发售，假期最后一天（4月6日）车票将于3月23日开售。本次清明假期铁路运输周期为4月3日至4月7日，共计5天。深圳铁路部门预计发送旅客181.4万人次，其中深圳北站预计发送旅客118.8万人次。客流以短途扫墓、踏青流为主，旅游流为辅，呈现出“前期集中出行、增速较快，后期分散返程、较为平缓”的特点。',NULL,NULL,NULL,'data/articles/daa31028d3.md','success',NULL,'2026-03-22 02:44:37.612035','2026-03-22 02:44:37.612038');
INSERT INTO articles VALUES(27,11,'https://36kr.com/newsflashes/3733429003616261?f=rss','被AI“偷走”声音 配音演员集体维权：希望构建合法共存生态','近日，多名配音演员相继公开发声，反对未经演员知情同意，擅自采集其声音素材用于AI训练、音色合成及商业变现的行为。从《甜蜜蜜》里的黎小军，到《无间道》中的刘建明，配音演员叶清塑造了许多经典的人物形象。就在不久前，短视频平台上出现了一集AI生成的短剧，许多观众通过弹幕刷屏：主人公的旁白是“叶清老师的声音”。接受记者采访时，叶清坦言，AI短剧里对他的音色还原度极高。类似的经历在配音行业中屡见不鲜。配音导演、配音演员李龙滨也经常成为这种侵权行为的受害者。',NULL,NULL,NULL,'data/articles/4ac4bd1231.md','success',NULL,'2026-03-22 02:44:37.615548','2026-03-22 02:44:37.615551');
INSERT INTO articles VALUES(28,11,'https://36kr.com/newsflashes/3733421955760391?f=rss','中国充电联盟：1-2月充电基础设施增量为91.8万个','据中国充电联盟消息，2026年1-2月，充电基础设施增量为91.8万个，同比上升44.8%。其中公共充电设施增量为11.7万个，同比减少53.8%，私人充电设施增量为80.1万个，同比上升110.4%。',NULL,NULL,NULL,'data/articles/3a3d6223bc.md','success',NULL,'2026-03-22 02:44:37.618625','2026-03-22 02:44:37.618628');
INSERT INTO articles VALUES(29,11,'https://36kr.com/newsflashes/3732477835346184?f=rss','协创数据：公司及下属企业均与超微电脑没有任何业务合作关系','36氪获悉，协创数据在互动平台表示，公司及下属企业均与超微电脑没有任何业务合作关系。请勿轻信市场传闻，公司就近期互联网及市场上出现的针对公司的不实信息，已正式发布严正声明，对相关虚假言论予以澄清驳斥。公司已委托其常年法律顾问广东信达律师事务所就上述不实信息开展全面核查，并全权负责相关维权事宜，依法维护公司及全体股东的合法权益。',NULL,NULL,NULL,'data/articles/e063aa1d27.md','success',NULL,'2026-03-22 02:44:37.621294','2026-03-22 02:44:37.621297');
INSERT INTO articles VALUES(30,11,'https://36kr.com/newsflashes/3732458470441217?f=rss','阿尔凯默斯在印度推出司美格鲁肽注射液','据报道，阿尔凯默斯（Alkem Labs）在印度推出司美格鲁肽注射液，产品品牌名为Semasize、Obesema及Hepaglide，每周疗程价格最低为450卢比，每月四剂售价1800卢比。（第一财经）',NULL,NULL,NULL,'data/articles/7477ecb8e7.md','success',NULL,'2026-03-22 02:44:37.624579','2026-03-22 02:44:37.624582');
INSERT INTO articles VALUES(31,11,'https://36kr.com/newsflashes/3732458131783689?f=rss','国家级电力人工智能中试基地迎首批企业，华为、中兴、百度等入驻','3月20日，国家人工智能应用中试基地（能源领域电力方向）2026年联盟工作会议暨首期生态活动在广州举行。南网数字集团人工智能研究中心、华为、中兴、百度等8家企业机构，作为首批代表正式入驻中试基地。第一财经记者了解到，作为电力人工智能领域的“桥梁型平台”，中试基地已成功连接100多家不同领域单位，推动资源高效共享与协同拓展。此次首批入驻的8家企业机构，还包括天合科技、南瑞信通、天数智芯、泰豪软件等。（第一财经）',NULL,NULL,NULL,'data/articles/4385f37479.md','success',NULL,'2026-03-22 02:44:37.627700','2026-03-22 02:44:37.627703');
INSERT INTO articles VALUES(32,11,'https://36kr.com/newsflashes/3732456438481157?f=rss','亚马逊正开发整合AI能力且与其语音助手Alexa同步的智能手机','据媒体周五（3月20日）援引知情人士消息报道，亚马逊正在开发一款整合人工智能能力并能与公司语音助手Alexa同步的智能手机。该项目内部代号为“Transformer”，由亚马逊设备与服务部门负责研发，定位为一款高度个性化的移动设备。该手机的核心在于通过AI技术简化用户操作，可能无需传统应用商店即可使用功能，旨在让用户更便捷地使用亚马逊购物、Prime Video和Grubhub等服务。（新浪财经）',NULL,NULL,NULL,'data/articles/1d4c5fa8aa.md','success',NULL,'2026-03-22 02:44:37.631940','2026-03-22 02:44:37.631943');
INSERT INTO articles VALUES(33,11,'https://36kr.com/newsflashes/3732454808436740?f=rss','我国自主研发的期刊评价体系正式发布','3月21日，东壁科技数据联合中国医学科学院医学信息研究所等单位在上海正式发布全球医学与生命科学高质量期刊列表，这也是我国自主研发的期刊评价体系。科研团队从全球4万多本医学、生命科学期刊中遴选出4027本高质量医学期刊、3064本高质量生命科学期刊，并根据期刊引文网络层级结构中的学术影响力，将遴选出的高质量期刊划分为ABCD四个等级，分别代表所在学科领域的顶级期刊、具有较高学术威望的期刊、具有良好学术声誉的期刊、学术水平得到广泛认可的期刊。（央视新闻）',NULL,NULL,NULL,'data/articles/d19eae030a.md','success',NULL,'2026-03-22 02:44:37.635031','2026-03-22 02:44:37.635035');
INSERT INTO articles VALUES(34,11,'https://36kr.com/newsflashes/3732454087786501?f=rss','欧洲央行管委Nagel：如有必要，可以迅速行动应对通胀风险','欧洲央行管理委员会成员、德国央行行长Joachim Nagel表示，如果有迹象显示伊朗战争导致通胀预期超过2%，欧洲央行已准备好迅速作出回应。Nagel在德国戈斯拉尔发表讲话时说，虽然货币政策无法阻止能源冲击造成通胀在短期内偏离目标，但如果实际价格涨幅产生波及效应、可能影响中期走势，欧洲央行就必须采取行动。（新浪财经）',NULL,NULL,NULL,'data/articles/567b5d2a9f.md','success',NULL,'2026-03-22 02:44:37.637912','2026-03-22 02:44:37.637915');
INSERT INTO articles VALUES(35,11,'https://36kr.com/newsflashes/3732452663804162?f=rss','华为将发布首款风冷散热手机','华为将于3月23日举行的华为春季新品发布会上发布华为Mate80系列全新版本，其首次在圆形镜头模组内部集成了一颗主动散热风扇，是华为首款内置主动风冷散热系统的手机。（证券时报）',NULL,NULL,NULL,'data/articles/87347c5611.md','success',NULL,'2026-03-22 02:44:37.640914','2026-03-22 02:44:37.640917');
INSERT INTO articles VALUES(36,11,'https://36kr.com/newsflashes/3732449006502148?f=rss','我国电动汽车充电基础设施总数达2101.0万个','3月21日，国家能源局发布2026年2月全国电动汽车充电设施数据。根据国家充电设施监测服务平台数据，截至2026年2月底，我国电动汽车充电基础设施（枪）总数达到2101.0万个，同比增长47.8%。其中：公共充电设施（枪）483.4万个，同比增长28.8%，公共充电设施额定总功率达到2.29亿千瓦，平均功率约为47.41千瓦；私人充电设施（枪）1617.6万个，同比增长54.6%，私人充电设施报装用电容量达到1.41亿千伏安。（央视新闻）',NULL,NULL,NULL,'data/articles/f2c6640dd9.md','success',NULL,'2026-03-22 02:44:37.643773','2026-03-22 02:44:37.643777');
INSERT INTO articles VALUES(37,11,'https://36kr.com/newsflashes/3732441440665859?f=rss','LiblibAI发布AI视频创作平台LibTV','36氪获悉，近日，LiblibAI正式发布AI视频创作平台LibTV，上线首日访问量突破10万。据了解，LibTV首创双入口模式，一面是专业创作者，另一面是Agent，将其视作“新型用户”，为Agent提供可以直接调度的视频生产能力。',NULL,NULL,NULL,'data/articles/77d4d868f4.md','success',NULL,'2026-03-22 02:44:37.646705','2026-03-22 02:44:37.646708');
INSERT INTO articles VALUES(38,11,'https://36kr.com/newsflashes/3732411719794952?f=rss','胖东来正与酒鬼酒洽谈600元新品','胖东来与酒鬼酒拟推出次高端白酒新品。知情人士透露：“新品定价600-800元，双方已就该产品洽谈了一段时间。”去年7月，酒鬼酒与胖东来推出首款联名产品“酒鬼·自由爱”。该产品面向大众市场，定价200元，综合成本168.26元，毛利率15.87%。新品上市后曾一度热销，线上和线下均出现短暂断货。（酒业内参）',NULL,NULL,NULL,'data/articles/559c37e4a9.md','success',NULL,'2026-03-22 02:44:37.651920','2026-03-22 02:44:37.651922');
INSERT INTO articles VALUES(39,11,'https://36kr.com/newsflashes/3732387328655360?f=rss','马斯克：Optimus+PV将是首个冯诺依曼探测器','36氪获悉，马斯克表示Optimus+PV将是首个冯诺依曼探测器，它完全能够利用太空中的原材料进行自我复制。',NULL,NULL,NULL,'data/articles/59c3269b57.md','success',NULL,'2026-03-22 02:44:37.655144','2026-03-22 02:44:37.655147');
INSERT INTO articles VALUES(40,11,'https://36kr.com/newsflashes/3732341580841218?f=rss','雷军官宣：XiaomiMiMo首周限免开放','36氪获悉，雷军发博表示：Xiaomi MiMo联合OpenClaw、OpenCode、KiloCode、Cline和BLACKBOXAI五大主流Agent框架，首周限免开放。欢迎国内开发者试用。',NULL,NULL,NULL,'data/articles/5f521e8407.md','success',NULL,'2026-03-22 02:44:37.659296','2026-03-22 02:44:37.659300');
