INSERT INTO articles VALUES(128,11,'https://36kr.com/newsflashes/3733477270896902?f=rss','软银计划在美国俄亥俄州建设5000亿美元的巨型AI数据中心','软银首席执行官孙正义当地时间3月20日表示，软银集团正筹划在美国俄亥俄州打造一个规模庞大的数据中心基础设施项目，将向这一单一项目投入5000亿美元。软银拟在美国能源部拥有的一处前铀浓缩设施旧址建设该人工智能计算综合体，其用电规模可达10吉瓦，预计该数据中心项目第一阶段将涵盖800兆瓦电力，耗资300亿至400亿美元，并将于2028年初完工。该项目将采用价值约330亿美元的燃气发电，这些发电设施将在本十年末之前安装完毕。',NULL,NULL,NULL,'data/articles/6e82c75e9b.md','success',NULL,'2026-03-22 03:06:16.885088','2026-03-22 03:06:16.885093');
INSERT INTO articles VALUES(129,11,'https://36kr.com/newsflashes/3733476689592577?f=rss','2026无锡马拉松鸣枪开跑 多人刷新马拉松项目个人最好成绩','北京时间3月22日，在2026无锡马拉松比赛中，男子组冠军是来自埃塞俄比亚的选手Kemal HUSEN，成绩为02:07:07。来自中国贵州的马拉松新锐毛金虎跑出02:07:36的好成绩，获得亚军，刷新个人最好成绩。',NULL,NULL,NULL,'data/articles/450bd0a004.md','success',NULL,'2026-03-22 03:06:16.889107','2026-03-22 03:06:16.889110');
